import React from "react";

export default function Forecast({ city, forecastData = [] }) {
  const sampleData = [
    { day: "Mon", icon: "🌤️", high: "30°C", low: "20°C" },
    { day: "Tue", icon: "🌧️", high: "28°C", low: "19°C" },
    { day: "Wed", icon: "⛅", high: "31°C", low: "21°C" },
    { day: "Thu", icon: "🌩️", high: "27°C", low: "18°C" },
    { day: "Fri", icon: "☀️", high: "33°C", low: "22°C" },
    { day: "Sat", icon: "⛅", high: "29°C", low: "19°C" },
    { day: "Sun", icon: "🌧️", high: "27°C", low: "18°C" },
  ];
  const data = forecastData.length ? forecastData : sampleData;

  return (
    <div className="w-full">
      {/* Desktop header */}
      <div className="hidden sm:block mb-4">
        <h2 className="text-xl font-semibold text-white text-center drop-shadow-md">
          {city} — 16-Day Forecast
        </h2>
      </div>

      {/* Mobile: one-per-line */}
      <div className="sm:hidden space-y-3">
        {data.map((item, idx) => (
          <div
            key={idx}
            className="w-full flex items-center justify-between bg-black/60 backdrop-blur-md text-white rounded-xl px-4 py-3 shadow-lg"
          >
            <div className="flex items-center space-x-4">
              <span className="text-lg font-medium">{item.day}</span>
              <span className="text-2xl">{item.icon}</span>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-lg font-semibold">{item.high}</span>
              <span className="text-gray-300">{item.low}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Desktop: 4 per row */}
      <div className="hidden sm:grid sm:grid-cols-4 gap-4">
        {data.map((item, idx) => (
          <div
            key={idx}
            className="bg-black/60 backdrop-blur-md text-white rounded-xl p-4 flex flex-col justify-center items-center shadow-lg aspect-square hover:ring-1 hover:ring-purple-500/40 transition"
          >
            <span className="text-lg font-medium">{item.day}</span>
            <span className="text-3xl">{item.icon}</span>
            <span className="text-lg font-semibold">{item.high}</span>
            <span className="text-gray-300">{item.low}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
